window.POM_QUESTION_BANK = {"topics": [{"id": "cellular-biology", "name": "Cellular Biology", "counts": {"sba": 20, "vsaq": 18, "saq": 12}}, {"id": "haematology", "name": "Haematology", "counts": {"sba": 20, "vsaq": 18, "saq": 12}}, {"id": "immunity", "name": "Immunity", "counts": {"sba": 20, "vsaq": 18, "saq": 12}}, {"id": "genetics", "name": "Genetics", "counts": {"sba": 20, "vsaq": 18, "saq": 12}}], "questions": {"cellular-biology": {"sba": [{"q": "Which reaction type describes the breakdown of larger molecules with release of energy stored as ATP?", "a": "Catabolic", "options": ["Catabolic", "Anabolic", "Isomerisation", "Ligation"], "lecture": "2.1 Cell Metabolism I", "level": "recall"}, {"q": "Where does glycolysis occur in a eukaryotic cell?", "a": "Cytosol", "options": ["Cytosol", "Mitochondrial matrix", "Inner mitochondrial membrane", "Rough ER"], "lecture": "2.1 Cell Metabolism I", "level": "recall"}, {"q": "A patient develops lactic acidosis during severe hypoxia. Which metabolic need does lactate production primarily meet?", "a": "Regeneration of NAD+ so glycolysis can continue", "options": ["Regeneration of NAD+ so glycolysis can continue", "Direct production of 36 ATP per glucose", "Feeding acetyl-CoA into the TCA cycle", "Synthesis of NADPH for anabolism"], "lecture": "2.1 Cell Metabolism I", "level": "application", "explanation": "In hypoxia oxidative phosphorylation stops; converting pyruvate to lactate regenerates NAD+ for GAPDH (glycolysis step 6)."}, {"q": "Which coenzyme from the pentose phosphate pathway is especially important for protecting red cells from oxidative damage?", "a": "NADPH", "options": ["NADPH", "NADH", "FADH2", "Coenzyme A"], "lecture": "2.1 Cell Metabolism I", "level": "understanding"}, {"q": "Phosphofructokinase-1 is inhibited by high ATP. What does this illustrate?", "a": "Feedback inhibition of a committed glycolytic step when energy is plentiful", "options": ["Feedback inhibition of a committed glycolytic step when energy is plentiful", "Irreversible activation of glycogenolysis", "Allosteric activation of pyruvate dehydrogenase by ATP", "Competitive inhibition of hexokinase by glucose"], "lecture": "2.6 Integration of Metabolism", "level": "inference"}, {"q": "Creatine kinase catalyses reversible transfer of phosphate between creatine and ADP. When is the creatine phosphate store most useful?", "a": "Brief high-intensity muscle work when ATP demand spikes", "options": ["Brief high-intensity muscle work when ATP demand spikes", "Overnight fasting hepatic gluconeogenesis", "Long-term storage of fatty acids in adipose tissue", "DNA replication in S phase"], "lecture": "2.4 Creatine Kinase", "level": "application"}, {"q": "Statins inhibit HMG-CoA reductase. What is the direct metabolic consequence?", "a": "Reduced de novo cholesterol synthesis", "options": ["Reduced de novo cholesterol synthesis", "Increased bile acid conjugation only", "Blockade of fatty acid β-oxidation", "Inhibition of LDL receptor transcription only"], "lecture": "2.5 Cholesterol", "level": "application"}, {"q": "Which junctional complex forms a belt-like seal that limits paracellular diffusion between epithelial cells?", "a": "Tight junction (zonula occludens)", "options": ["Tight junction (zonula occludens)", "Gap junction", "Hemidesmosome", "Focal adhesion"], "lecture": "2.3 Epithelial Cells and Tissues", "level": "recall"}, {"q": "A tumour suppressor gene normally restrains the cell cycle. Loss of both alleles typically contributes to cancer via which mechanism?", "a": "Loss of a brake on proliferation / genomic integrity", "options": ["Loss of a brake on proliferation / genomic integrity", "Gain of a constitutively active growth signal", "Increased DNA repair fidelity only", "Enhanced contact inhibition"], "lecture": "2.15 Cancer", "level": "understanding"}, {"q": "During acute inflammation, which event best explains endothelial gaps and protein-rich exudate?", "a": "Increased vascular permeability", "options": ["Increased vascular permeability", "Decreased hydrostatic pressure only", "Complete thrombosis of all capillaries", "Immediate fibrosis of the interstitium"], "lecture": "2.13 Inflammation", "level": "understanding"}, {"q": "Apoptosis differs from necrosis mainly because apoptotic cell death is typically:", "a": "Programmed, energy-dependent, and non-inflammatory if orderly", "options": ["Programmed, energy-dependent, and non-inflammatory if orderly", "Always caused by trauma with membrane rupture and inflammation", "Identical to coagulative necrosis histologically", "Independent of caspase pathways"], "lecture": "2.11 Cell Fate and Injury", "level": "understanding"}, {"q": "A G-protein-coupled receptor activates Gs. What is the immediate next effect on adenylyl cyclase?", "a": "Increased cAMP production", "options": ["Increased cAMP production", "Cleavage of PIP2 to IP3 and DAG", "Opening of ligand-gated Na+ channels only", "Direct phosphorylation of tyrosine residues on the receptor"], "lecture": "2.10 Cell Signalling", "level": "recall"}, {"q": "In Michaelis–Menten kinetics, a competitive inhibitor typically:", "a": "Increases apparent Km without changing Vmax", "options": ["Increases apparent Km without changing Vmax", "Decreases Vmax without changing Km", "Increases both Km and Vmax equally", "Has no effect on the Lineweaver–Burk plot"], "lecture": "2.14 Enzyme Kinetics", "level": "understanding"}, {"q": "Which fluid compartment contains the largest volume of body water in a typical adult?", "a": "Intracellular fluid", "options": ["Intracellular fluid", "Interstitial fluid", "Plasma", "Transcellular fluid"], "lecture": "2.12 Fluid Compartments and Solutes", "level": "recall"}, {"q": "A patient has hyponatraemia with low plasma osmolality. Water shifts tend to move:", "a": "Into cells, risking cellular swelling", "options": ["Into cells, risking cellular swelling", "Out of cells, causing crenation only", "Only into the plasma from interstitial fluid with no cell effect", "Only into bone mineral stores"], "lecture": "2.12 Fluid Compartments and Solutes", "level": "application"}, {"q": "Collagen fibres in the extracellular matrix primarily provide:", "a": "Tensile strength", "options": ["Tensile strength", "Elastic recoil only", "Hormone storage only", "ATP generation"], "lecture": "2.9 Extracellular Matrix", "level": "recall"}, {"q": "Which phase of the cell cycle is DNA replicated?", "a": "S phase", "options": ["S phase", "G0", "M phase cytokinesis only", "G1 checkpoint arrest only"], "lecture": "2.8 Cell Replication", "level": "recall"}, {"q": "Oncogenes are most accurately described as:", "a": "Mutated/activated versions of proto-oncogenes that drive proliferation", "options": ["Mutated/activated versions of proto-oncogenes that drive proliferation", "Genes that always prevent DNA replication", "Identical to tumour suppressor genes", "Only viral genes with no cellular counterparts"], "lecture": "2.15 Cancer", "level": "understanding"}, {"q": "A biopsy shows loss of normal tissue architecture with nuclear atypia and invasion through basement membrane. This best describes:", "a": "Malignant neoplasm", "options": ["Malignant neoplasm", "Hyperplasia only", "Metaplasia only", "Hypertrophy only"], "lecture": "2.16 Histopathology", "level": "application"}, {"q": "Which statement best links inflammation to tissue repair?", "a": "Inflammation clears injurious agents and sets the stage for healing, but chronic inflammation can drive fibrosis", "options": ["Inflammation clears injurious agents and sets the stage for healing, but chronic inflammation can drive fibrosis", "Inflammation always regenerates tissue without scarring", "Repair never involves angiogenesis", "Neutrophils alone produce collagen for scar formation"], "lecture": "2.13 Inflammation", "level": "inference"}], "vsaq": [{"q": "Name the cytosolic pathway that converts glucose to pyruvate.", "a": "Glycolysis", "lecture": "2.1 Cell Metabolism I", "level": "recall"}, {"q": "Which enzyme phosphorylates glucose in most tissues?", "a": "Hexokinase", "lecture": "2.1 Cell Metabolism I", "level": "recall"}, {"q": "How many net ATP are produced from anaerobic glycolysis per glucose?", "a": "2", "lecture": "2.1 Cell Metabolism I", "level": "recall"}, {"q": "Name the mitochondrial cycle that oxidises acetyl-CoA.", "a": ["TCA cycle", "Krebs cycle", "Citric acid cycle"], "lecture": "2.1 Cell Metabolism I", "level": "recall"}, {"q": "Which organelle houses oxidative phosphorylation?", "a": "Mitochondria", "lecture": "2.2 Cell Metabolism II", "level": "recall"}, {"q": "Statins inhibit which rate-limiting enzyme of cholesterol synthesis?", "a": "HMG-CoA reductase", "lecture": "2.5 Cholesterol", "level": "recall"}, {"q": "Name the main plasma lipoprotein that delivers cholesterol to tissues via LDL receptors.", "a": "LDL", "lecture": "2.5 Cholesterol", "level": "recall"}, {"q": "Which kinase buffers ATP using creatine phosphate?", "a": "Creatine kinase", "lecture": "2.4 Creatine Kinase", "level": "recall"}, {"q": "Name the programmed form of cell death involving caspases.", "a": "Apoptosis", "lecture": "2.11 Cell Fate and Injury", "level": "recall"}, {"q": "Which cell-cycle phase follows G1?", "a": "S phase", "lecture": "2.8 Cell Replication", "level": "recall"}, {"q": "Name the second messenger produced by adenylyl cyclase.", "a": "cAMP", "lecture": "2.10 Cell Signalling", "level": "recall"}, {"q": "What is the most abundant cation in intracellular fluid?", "a": ["K+", "Potassium"], "lecture": "2.12 Fluid Compartments and Solutes", "level": "recall"}, {"q": "Name the cardinal feature of inflammation meaning redness.", "a": "Rubor", "lecture": "2.13 Inflammation", "level": "recall"}, {"q": "A competitive inhibitor increases which Michaelis–Menten parameter?", "a": "Km", "lecture": "2.14 Enzyme Kinetics", "level": "understanding"}, {"q": "Name a classic tumour suppressor gene mutated in many cancers.", "a": ["p53", "TP53"], "lecture": "2.15 Cancer", "level": "recall"}, {"q": "Which ECM protein provides tensile strength?", "a": "Collagen", "lecture": "2.9 Extracellular Matrix", "level": "recall"}, {"q": "Tight junctions primarily limit which transport route?", "a": "Paracellular", "lecture": "2.3 Epithelial Cells and Tissues", "level": "understanding"}, {"q": "NADPH is generated mainly by which pathway?", "a": ["Pentose phosphate pathway", "PPP", "HMP shunt"], "lecture": "2.1 Cell Metabolism I", "level": "recall"}], "saq": [{"q": "Explain why glycolysis can continue under anaerobic conditions while the TCA cycle and oxidative phosphorylation cannot, and state the key molecule regenerated by lactate dehydrogenase.", "a": "Without oxygen, the electron transport chain stops so NADH cannot be reoxidised there and the TCA cycle slows. Glycolysis can still yield net ATP if NAD+ is regenerated; LDH reduces pyruvate to lactate, oxidising NADH to NAD+, which allows GAPDH to keep working.", "lecture": "2.1 Cell Metabolism I", "level": "understanding"}, {"q": "Compare catabolic and anabolic pathways with respect to energy and molecular size, giving one example of each.", "a": "Catabolic pathways break larger molecules into smaller ones and typically release energy (e.g. glycolysis, β-oxidation). Anabolic pathways build larger molecules from smaller precursors and require energy input from ATP/NADPH (e.g. glycogen synthesis, fatty acid synthesis).", "lecture": "2.1 Cell Metabolism I", "level": "understanding"}, {"q": "A patient on a statin asks how the drug lowers LDL cholesterol. Outline the mechanism linking HMG-CoA reductase inhibition to increased hepatic LDL clearance.", "a": "Statins inhibit HMG-CoA reductase, reducing hepatocyte cholesterol synthesis. Lower intracellular cholesterol upregulates LDL receptor expression, increasing hepatic uptake of circulating LDL and thereby lowering plasma LDL.", "lecture": "2.5 Cholesterol", "level": "application"}, {"q": "Describe how creatine phosphate supports short bursts of intense muscle activity.", "a": "Muscle stores creatine phosphate. Creatine kinase transfers the phosphate to ADP to regenerate ATP rapidly when demand suddenly rises, bridging the gap until glycolysis and oxidative metabolism catch up.", "lecture": "2.4 Creatine Kinase", "level": "application"}, {"q": "Distinguish apoptosis from necrosis in terms of mechanism, morphology, and inflammatory consequence.", "a": "Apoptosis is programmed, ATP-dependent, involves caspase cascades, cell shrinkage and apoptotic bodies, and is usually non-inflammatory when cleared by phagocytes. Necrosis is accidental cell death from severe injury, with membrane rupture, cellular swelling, and typically provokes inflammation.", "lecture": "2.11 Cell Fate and Injury", "level": "understanding"}, {"q": "Outline the sequence of vascular events in acute inflammation and how they produce the cardinal signs.", "a": "Transient vasoconstriction may occur, then arteriolar vasodilation increases blood flow (rubor, calor). Increased permeability allows protein-rich exudate into tissues (tumor). Chemical mediators and pressure contribute to dolor; loss of function may follow.", "lecture": "2.13 Inflammation", "level": "recall"}, {"q": "Explain how a gain-of-function mutation in a proto-oncogene differs from loss of a tumour suppressor in driving cancer.", "a": "Proto-oncogene activation (e.g. constitutively active growth signalling) acts in a dominant fashion—one allele can drive proliferation. Tumour suppressors normally restrain growth or protect the genome; typically both alleles must be lost (two-hit) for full effect.", "lecture": "2.15 Cancer", "level": "inference"}, {"q": "A GPCR coupled to Gs is activated by ligand. Trace the pathway from receptor to a typical cellular response involving protein kinase A.", "a": "Ligand-bound receptor activates Gs, which stimulates adenylyl cyclase to make cAMP. cAMP activates protein kinase A, which phosphorylates target proteins, altering enzyme activity or gene transcription depending on the cell type.", "lecture": "2.10 Cell Signalling", "level": "application"}, {"q": "Using Starling principles, explain how hypoalbuminaemia can cause oedema.", "a": "Plasma albumin is a major contributor to colloid osmotic (oncotic) pressure that retains fluid in capillaries. Low albumin reduces oncotic pressure, so net filtration increases and fluid accumulates in the interstitium as oedema.", "lecture": "2.12 Fluid Compartments and Solutes", "level": "application"}, {"q": "Describe how competitive and non-competitive inhibition differ on a Lineweaver–Burk plot.", "a": "Competitive inhibition increases apparent Km (x-intercept changes) but Vmax is unchanged (same y-intercept). Non-competitive inhibition decreases Vmax (y-intercept rises) while Km is typically unchanged.", "lecture": "2.14 Enzyme Kinetics", "level": "understanding"}, {"q": "Explain why epithelial polarity and tight junctions matter for barrier function in gut or kidney tubules.", "a": "Polarised epithelia have distinct apical and basolateral domains with different transporters. Tight junctions seal the paracellular route, forcing selective transcellular transport and maintaining gradients and barrier integrity.", "lecture": "2.3 Epithelial Cells and Tissues", "level": "inference"}, {"q": "Outline the roles of collagen and elastin in the extracellular matrix and give one tissue example for each.", "a": "Collagen provides tensile strength (e.g. tendon, dermis). Elastin provides elastic recoil (e.g. large arteries, lung). Together they determine mechanical properties of connective tissues.", "lecture": "2.9 Extracellular Matrix", "level": "recall"}]}, "haematology": {"sba": [{"q": "What is the approximate lifespan of a normal circulating erythrocyte?", "a": "120 days", "options": ["120 days", "10 days", "1 year", "24 hours"], "lecture": "3.1 Red Blood Cells", "level": "recall"}, {"q": "Haemoglobin’s oxygen-binding curve is sigmoidal mainly because of:", "a": "Cooperative binding between haemoglobin subunits", "options": ["Cooperative binding between haemoglobin subunits", "Irreversible covalent binding of O2 to iron", "Only plasma dissolved oxygen", "Absence of allosteric effectors"], "lecture": "3.2 Haemoglobin Spectrophotometry and Electrophoresis", "level": "understanding"}, {"q": "A right shift of the oxygen dissociation curve (increased P50) means haemoglobin has:", "a": "Lower affinity for oxygen, facilitating unloading in tissues", "options": ["Lower affinity for oxygen, facilitating unloading in tissues", "Higher affinity, impairing tissue unloading", "No change in affinity", "Inability to bind CO2"], "lecture": "3.2 Haemoglobin Spectrophotometry and Electrophoresis", "level": "understanding"}, {"q": "Mean corpuscular volume (MCV) is low in which class of anaemia?", "a": "Microcytic anaemia", "options": ["Microcytic anaemia", "Macrocytic anaemia", "Normocytic anaemia only", "Haemolytic anaemia only"], "lecture": "3.3 Red Blood Cell Parameters", "level": "recall"}, {"q": "A patient has microcytic hypochromic anaemia. Which diagnosis is most consistent as a common cause?", "a": "Iron deficiency", "options": ["Iron deficiency", "Vitamin B12 deficiency", "Folate deficiency", "Acute blood loss with normal iron stores only"], "lecture": "3.4 Tales from the Haematology Clinic I", "level": "application"}, {"q": "Neutrophilia with left shift is most suggestive of:", "a": "Acute bacterial infection", "options": ["Acute bacterial infection", "Chronic parasitic infection only", "Immediate type I hypersensitivity alone", "Vitamin B12 deficiency alone"], "lecture": "3.5 White Blood Cells", "level": "application"}, {"q": "Eosinophilia is classically associated with:", "a": "Parasitic infection or allergy", "options": ["Parasitic infection or allergy", "Only acute pyogenic bacterial infection", "Only iron deficiency", "Only thrombocytopenia"], "lecture": "3.5 White Blood Cells", "level": "recall"}, {"q": "On a blood film, schistocytes (fragmented red cells) raise concern for:", "a": "Microangiopathic haemolysis", "options": ["Microangiopathic haemolysis", "Iron deficiency alone", "Hypothyroidism alone", "Vitamin C deficiency alone"], "lecture": "3.6 Diagnostic Role of the Blood Film", "level": "application"}, {"q": "Primary haemostasis mainly involves:", "a": "Platelet adhesion and aggregation forming a platelet plug", "options": ["Platelet adhesion and aggregation forming a platelet plug", "Only the extrinsic coagulation cascade generating fibrin", "Only fibrinolysis by plasmin", "Only complement activation"], "lecture": "3.8 Haemostasis", "level": "understanding"}, {"q": "Vitamin K is required for γ-carboxylation of which clotting factors?", "a": "II, VII, IX and X (and proteins C/S)", "options": ["II, VII, IX and X (and proteins C/S)", "Only factor VIII and vWF", "Only fibrinogen", "Only factor XIII"], "lecture": "3.8 Haemostasis", "level": "recall"}, {"q": "Warfarin inhibits vitamin K–dependent clotting factor synthesis. Which laboratory test is used to monitor warfarin therapy?", "a": "INR / prothrombin time", "options": ["INR / prothrombin time", "APTT alone", "Bleeding time alone", "ESR alone"], "lecture": "3.8 Haemostasis", "level": "application"}, {"q": "A patient of blood group A has which naturally occurring antibodies?", "a": "Anti-B", "options": ["Anti-B", "Anti-A", "Anti-A and anti-B", "Anti-D only"], "lecture": "3.9 Blood Transfusion", "level": "recall"}, {"q": "Which ABO type is the universal red-cell donor in emergencies (packed red cells)?", "a": "O", "options": ["O", "AB", "A", "B"], "lecture": "3.9 Blood Transfusion", "level": "recall"}, {"q": "Plasma is best defined as:", "a": "The liquid component of blood containing clotting factors", "options": ["The liquid component of blood containing clotting factors", "Plasma minus clotting factors (serum definition reversed)", "Only the cellular buffy coat", "Only haemoglobin solution"], "lecture": "3.10 Plasma", "level": "recall"}, {"q": "Serum differs from plasma because serum lacks:", "a": "Clotting factors consumed in clot formation", "options": ["Clotting factors consumed in clot formation", "All proteins", "Electrolytes", "Water"], "lecture": "3.10 Plasma", "level": "understanding"}, {"q": "Low haptoglobin with raised bilirubin and LDH supports which process?", "a": "Haemolysis", "options": ["Haemolysis", "Iron deficiency without haemolysis", "Dehydration only", "Polycythaemia vera only"], "lecture": "3.10 Plasma", "level": "inference"}, {"q": "Landsteiner’s law states that:", "a": "People make antibodies to ABO antigens they lack on their own RBCs", "options": ["People make antibodies to ABO antigens they lack on their own RBCs", "Everyone has anti-A and anti-B regardless of group", "Rh antibodies are always naturally occurring at birth", "Platelets determine ABO type"], "lecture": "3.9 Blood Transfusion", "level": "understanding"}, {"q": "Haemophilia A is due to deficiency of:", "a": "Factor VIII", "options": ["Factor VIII", "Factor IX", "Factor VII", "von Willebrand factor only"], "lecture": "3.8 Haemostasis", "level": "recall"}, {"q": "A raised MCV with hypersegmented neutrophils suggests which deficiency?", "a": "B12 or folate deficiency", "options": ["B12 or folate deficiency", "Iron deficiency", "Acute blood loss only", "G6PD deficiency only"], "lecture": "3.4 Tales from the Haematology Clinic I", "level": "application"}, {"q": "Which cell lineage produces platelets?", "a": "Megakaryocytes", "options": ["Megakaryocytes", "Erythroblasts only", "Myeloblasts only", "Plasma cells"], "lecture": "3.1 Red Blood Cells", "level": "recall"}], "vsaq": [{"q": "Approximate lifespan of a normal RBC?", "a": "120 days", "lecture": "3.1 Red Blood Cells", "level": "recall"}, {"q": "Name the oxygen-carrying protein in erythrocytes.", "a": "Haemoglobin", "lecture": "3.1 Red Blood Cells", "level": "recall"}, {"q": "What does a low MCV indicate?", "a": "Microcytosis", "lecture": "3.3 Red Blood Cell Parameters", "level": "understanding"}, {"q": "Name the most common cause of microcytic anaemia worldwide.", "a": "Iron deficiency", "lecture": "3.4 Tales from the Haematology Clinic I", "level": "recall"}, {"q": "Which white cell is most numerous in normal peripheral blood?", "a": "Neutrophil", "lecture": "3.5 White Blood Cells", "level": "recall"}, {"q": "Name the fragmented red cells seen in microangiopathic haemolysis.", "a": "Schistocytes", "lecture": "3.6 Diagnostic Role of the Blood Film", "level": "recall"}, {"q": "Primary haemostasis centres on which blood element?", "a": "Platelets", "lecture": "3.8 Haemostasis", "level": "recall"}, {"q": "Warfarin monitoring uses which standardised ratio?", "a": "INR", "lecture": "3.8 Haemostasis", "level": "recall"}, {"q": "Vitamin K–dependent factors include II, VII, IX and which other?", "a": "X", "lecture": "3.8 Haemostasis", "level": "recall"}, {"q": "Haemophilia A: which factor is deficient?", "a": ["Factor VIII", "VIII"], "lecture": "3.8 Haemostasis", "level": "recall"}, {"q": "Universal red-cell donor ABO group?", "a": "O", "lecture": "3.9 Blood Transfusion", "level": "recall"}, {"q": "Universal plasma donor ABO group?", "a": "AB", "lecture": "3.9 Blood Transfusion", "level": "recall"}, {"q": "Plasma minus clotting factors equals?", "a": "Serum", "lecture": "3.10 Plasma", "level": "recall"}, {"q": "Most abundant plasma protein?", "a": "Albumin", "lecture": "3.10 Plasma", "level": "recall"}, {"q": "Name the iron-transport protein in plasma.", "a": "Transferrin", "lecture": "3.10 Plasma", "level": "recall"}, {"q": "Low haptoglobin suggests what process?", "a": "Haemolysis", "lecture": "3.10 Plasma", "level": "inference"}, {"q": "P50 reflects haemoglobin’s affinity for which gas?", "a": "Oxygen", "lecture": "3.2 Haemoglobin Spectrophotometry and Electrophoresis", "level": "understanding"}, {"q": "Name the pluripotent stem cells giving rise to blood lineages.", "a": ["HSCs", "Haemopoietic stem cells", "Hematopoietic stem cells"], "lecture": "3.1 Red Blood Cells", "level": "recall"}], "saq": [{"q": "Explain cooperative oxygen binding in haemoglobin and why the dissociation curve is sigmoidal.", "a": "Binding of O2 to one subunit increases affinity of remaining subunits (positive cooperativity). This produces a sigmoidal curve: steep unloading over tissue PO2 ranges while still loading efficiently in the lungs.", "lecture": "3.2 Haemoglobin Spectrophotometry and Electrophoresis", "level": "understanding"}, {"q": "A patient has fatigue, low haemoglobin, low MCV and low ferritin. Interpret these findings and outline first-line management principles.", "a": "Findings indicate iron-deficiency anaemia. Investigate and treat the cause of iron loss/poor intake/absorption, and replace iron (oral or IV as appropriate) while monitoring response (reticulocytes, Hb, ferritin).", "lecture": "3.4 Tales from the Haematology Clinic I", "level": "application"}, {"q": "Compare the roles of neutrophils, eosinophils and lymphocytes in host defence.", "a": "Neutrophils are first-line phagocytes against bacteria/fungi. Eosinophils contribute to defence against parasites and allergic inflammation. Lymphocytes mediate adaptive immunity (B cells antibodies; T cells cellular immunity/help).", "lecture": "3.5 White Blood Cells", "level": "understanding"}, {"q": "Describe primary versus secondary haemostasis.", "a": "Primary haemostasis: vascular spasm and platelet plug formation (adhesion via vWF/GPIb, aggregation via GPIIb/IIIa and fibrinogen). Secondary haemostasis: coagulation cascade generating thrombin and fibrin that stabilises the plug.", "lecture": "3.8 Haemostasis", "level": "recall"}, {"q": "Explain why group O red cells are preferred as emergency universal donor units, and why plasma compatibility differs.", "a": "Group O RBCs lack A and B antigens so are less likely to be haemolysed by recipient isoagglutinins. Plasma contains antibodies: AB plasma lacks anti-A/B and is the universal plasma donor, whereas O plasma contains both antibodies.", "lecture": "3.9 Blood Transfusion", "level": "inference"}, {"q": "A patient on warfarin has a high INR and minor bleeding. Explain the pharmacological basis and typical reversal approach in principle.", "a": "Warfarin blocks vitamin K epoxide reductase, reducing γ-carboxylation of factors II, VII, IX, X. Raised INR reflects impaired extrinsic pathway. Reversal may include withholding warfarin, vitamin K, and in serious bleeding prothrombin complex concentrate (per guidelines).", "lecture": "3.8 Haemostasis", "level": "application"}, {"q": "How can electrophoresis of haemoglobin help diagnose sickle cell disease or thalassaemia trait?", "a": "Different haemoglobins migrate differently based on charge. Patterns can identify HbS, quantify HbA2/HbF, and support diagnoses such as sickle cell disease versus trait or β-thalassaemia trait when combined with red-cell indices and clinical context.", "lecture": "3.2 Haemoglobin Spectrophotometry and Electrophoresis", "level": "application"}, {"q": "Outline why albumin is important for plasma oncotic pressure and drug transport.", "a": "Albumin is the most abundant plasma protein and a major contributor to colloid osmotic pressure, retaining fluid in the vascular space. It also binds and transports many hormones, fatty acids, ions and drugs.", "lecture": "3.10 Plasma", "level": "understanding"}, {"q": "Interpret a blood film showing spherocytes and polychromasia in a jaundiced patient.", "a": "Spherocytes suggest membrane loss (hereditary spherocytosis or immune haemolysis). Polychromasia indicates reticulocytosis—a marrow response to haemolysis or blood loss. With jaundice this supports haemolytic anaemia; further tests (DAT, bilirubin, LDH, haptoglobin) refine the cause.", "lecture": "3.6 Diagnostic Role of the Blood Film", "level": "inference"}, {"q": "Describe Landsteiner’s law and its relevance to ABO crossmatching.", "a": "Individuals produce antibodies against ABO antigens absent from their own red cells (e.g. group A has anti-B). Crossmatching must ensure donor RBCs lack antigens targeted by recipient antibodies to prevent acute haemolytic transfusion reactions.", "lecture": "3.9 Blood Transfusion", "level": "understanding"}, {"q": "Explain how MCV, MCH and RDW help classify anaemias.", "a": "MCV classifies micro/normo/macrocytic; MCH reflects haemoglobin content (hypochromia). RDW indicates anisocytosis—often raised early in iron deficiency or mixed deficiencies—helping narrow differential beyond a single index.", "lecture": "3.3 Red Blood Cell Parameters", "level": "application"}, {"q": "Why might a raised CRP and polyclonal rise in gamma-globulins appear together in infection?", "a": "CRP is an acute-phase reactant rising with inflammation/infection. Gamma-globulins include immunoglobulins; polyclonal increase reflects humoral response to infection. Together they support an inflammatory/infectious process rather than a monoclonal paraprotein alone.", "lecture": "3.10 Plasma", "level": "inference"}]}, "immunity": {"sba": [{"q": "Which statement best defines a virus?", "a": "An infectious obligate intracellular parasite", "options": ["An infectious obligate intracellular parasite", "A free-living prokaryote with peptidoglycan", "A fungus with chitin cell walls only", "A multicellular parasite with digestive tract"], "lecture": "4.10 Anti-Viral Agents", "level": "recall"}, {"q": "Live attenuated vaccines generally induce stronger cellular immunity than killed vaccines because they:", "a": "Replicate to a limited extent and engage broader immune pathways", "options": ["Replicate to a limited extent and engage broader immune pathways", "Contain only polysaccharides without protein", "Never stimulate memory B cells", "Are unable to induce antibodies"], "lecture": "4.13 Vaccination", "level": "understanding"}, {"q": "Type I hypersensitivity is mediated primarily by:", "a": "IgE and mast cell degranulation", "options": ["IgE and mast cell degranulation", "IgG against cell surfaces only", "Immune complex deposition only", "CD8 T-cell cytotoxicity only"], "lecture": "4.15 Hypersensitivity", "level": "recall"}, {"q": "Anaphylaxis is a medical emergency of which hypersensitivity type?", "a": "Type I", "options": ["Type I", "Type II", "Type III", "Type IV"], "lecture": "4.9 Anaphylaxis", "level": "recall"}, {"q": "First-line emergency treatment of anaphylaxis is:", "a": "Intramuscular adrenaline", "options": ["Intramuscular adrenaline", "Oral antihistamine alone", "IV antibiotics alone", "High-dose oral prednisolone alone as first step"], "lecture": "4.9 Anaphylaxis", "level": "application"}, {"q": "Central immune tolerance primarily develops in which primary lymphoid organs?", "a": "Thymus (T cells) and bone marrow (B cells)", "options": ["Thymus (T cells) and bone marrow (B cells)", "Only lymph nodes", "Only spleen red pulp", "Only Peyer’s patches"], "lecture": "4.7 Immune Tolerance", "level": "understanding"}, {"q": "CD8 cytotoxic T cells recognise antigen presented on:", "a": "MHC class I", "options": ["MHC class I", "MHC class II", "Only IgM", "Only complement C3b"], "lecture": "4.6 Lymphocytes", "level": "recall"}, {"q": "CD4 helper T cells typically recognise antigen on:", "a": "MHC class II", "options": ["MHC class II", "MHC class I only", "Only ABO antigens", "Only Toll-like receptors"], "lecture": "4.6 Lymphocytes", "level": "recall"}, {"q": "A pathogen that downregulates MHC class I on infected cells is most likely trying to evade:", "a": "CD8 T-cell recognition", "options": ["CD8 T-cell recognition", "Neutrophil chemotaxis only", "Complement alternative pathway only", "IgE-mediated allergy only"], "lecture": "4.8 Immune Evasion", "level": "inference"}, {"q": "β-lactam antibiotics inhibit bacterial growth mainly by targeting:", "a": "Peptidoglycan cell wall synthesis", "options": ["Peptidoglycan cell wall synthesis", "Viral reverse transcriptase", "Fungal ergosterol only", "Human ribosomes"], "lecture": "4.3 Antimicrobial Therapies", "level": "understanding"}, {"q": "Broad-spectrum antibiotics increase risk of C. difficile colitis mainly because they:", "a": "Disrupt protective gut flora allowing C. difficile overgrowth", "options": ["Disrupt protective gut flora allowing C. difficile overgrowth", "Directly mutate C. difficile toxin genes", "Stimulate IgE against C. difficile", "Inhibit gastric acid only"], "lecture": "4.5 Diagnostic Bacteriology II", "level": "application"}, {"q": "Secondary lymphoid organs (e.g. lymph nodes, spleen) are specialised for:", "a": "Adaptive immune activation and antigen encounter", "options": ["Adaptive immune activation and antigen encounter", "Only haematopoiesis of all lineages", "Only filtration of CSF", "Only production of digestive enzymes"], "lecture": "4.2 Lymphoid Tissues", "level": "understanding"}, {"q": "Herd immunity is most effective when:", "a": "A sufficient proportion of the population is immune, limiting transmission", "options": ["A sufficient proportion of the population is immune, limiting transmission", "Only one person is vaccinated", "Antibiotics are given to everyone weekly", "Pathogens cannot mutate ever"], "lecture": "4.13 Vaccination", "level": "understanding"}, {"q": "PCR amplifies nucleic acid. Which enzyme is classically heat-stable for thermal cycling?", "a": "Taq polymerase", "options": ["Taq polymerase", "Pepsin", "Amylase", "Trypsin"], "lecture": "4.11 Diagnostic Virology I", "level": "recall"}, {"q": "Acyclovir is particularly useful against which virus family?", "a": "Herpesviruses (e.g. HSV)", "options": ["Herpesviruses (e.g. HSV)", "All RNA viruses equally", "Only hepatitis C", "Only influenza A"], "lecture": "4.10 Anti-Viral Agents", "level": "application"}, {"q": "Type IV hypersensitivity differs from types I–III because it is:", "a": "T-cell mediated (delayed)", "options": ["T-cell mediated (delayed)", "Always IgE mediated", "Always complement independent and immediate within seconds", "Caused only by ABO mismatch"], "lecture": "4.15 Hypersensitivity", "level": "understanding"}, {"q": "Passive immunotherapy with IVIG provides:", "a": "Immediate but temporary antibody-mediated protection", "options": ["Immediate but temporary antibody-mediated protection", "Lifelong active memory without antigen", "Only cell-mediated memory CD8 clones", "Sterilisation of the gut microbiome"], "lecture": "4.13 Vaccination", "level": "inference"}, {"q": "Gram-positive bacteria typically stain purple because of:", "a": "A thick peptidoglycan layer retaining crystal violet", "options": ["A thick peptidoglycan layer retaining crystal violet", "An outer LPS membrane only", "Absence of cell wall", "Capsule made of RNA"], "lecture": "4.4 Diagnostic Bacteriology I", "level": "recall"}, {"q": "Which innate cells are especially important early sensors via pattern recognition receptors?", "a": "Macrophages and dendritic cells (among others)", "options": ["Macrophages and dendritic cells (among others)", "Only plasma cells", "Only mature erythrocytes", "Only megakaryocytes"], "lecture": "4.14 Immune Response to Infection", "level": "understanding"}, {"q": "A neonate tests antibody-positive for HIV. Why might PCR be preferred to confirm infection?", "a": "Maternal IgG can persist and confound antibody tests", "options": ["Maternal IgG can persist and confound antibody tests", "Neonates never produce any immune response", "PCR detects only maternal DNA", "Antibodies always mean active viral replication"], "lecture": "4.12 Diagnostic Virology II", "level": "application"}], "vsaq": [{"q": "Name the antibody class central to type I hypersensitivity.", "a": "IgE", "lecture": "4.15 Hypersensitivity", "level": "recall"}, {"q": "First-line drug for anaphylaxis?", "a": "Adrenaline", "lecture": "4.9 Anaphylaxis", "level": "recall"}, {"q": "CD8 T cells recognise antigen on which MHC class?", "a": ["MHC I", "MHC class I", "HLA class I"], "lecture": "4.6 Lymphocytes", "level": "recall"}, {"q": "CD4 T cells recognise antigen on which MHC class?", "a": ["MHC II", "MHC class II", "HLA class II"], "lecture": "4.6 Lymphocytes", "level": "recall"}, {"q": "Name the primary lymphoid organ for T-cell maturation.", "a": "Thymus", "lecture": "4.2 Lymphoid Tissues", "level": "recall"}, {"q": "β-lactams target synthesis of what bacterial structure?", "a": "Peptidoglycan", "lecture": "4.3 Antimicrobial Therapies", "level": "recall"}, {"q": "Name a live attenuated viral vaccine example.", "a": ["MMR", "Oral polio", "Yellow fever", "Varicella"], "lecture": "4.13 Vaccination", "level": "recall"}, {"q": "Herd immunity reduces what between hosts?", "a": "Transmission", "lecture": "4.13 Vaccination", "level": "understanding"}, {"q": "PCR uses which heat-stable polymerase classically?", "a": "Taq polymerase", "lecture": "4.11 Diagnostic Virology I", "level": "recall"}, {"q": "Acyclovir is a nucleoside analogue used mainly against?", "a": ["HSV", "Herpesviruses", "Herpes"], "lecture": "4.10 Anti-Viral Agents", "level": "recall"}, {"q": "Gram-positive organisms retain which primary stain?", "a": "Crystal violet", "lecture": "4.4 Diagnostic Bacteriology I", "level": "recall"}, {"q": "C. difficile colitis is linked to disruption of?", "a": ["Gut flora", "Microbiome", "Normal flora"], "lecture": "4.5 Diagnostic Bacteriology II", "level": "understanding"}, {"q": "Type IV hypersensitivity timing is described as?", "a": "Delayed", "lecture": "4.15 Hypersensitivity", "level": "recall"}, {"q": "Name the process deleting strongly self-reactive thymocytes.", "a": ["Negative selection", "Central tolerance"], "lecture": "4.7 Immune Tolerance", "level": "understanding"}, {"q": "Obligate intracellular parasite composed of nucleic acid in a protein coat?", "a": "Virus", "lecture": "4.1 Microbial Infection", "level": "recall"}, {"q": "IVIG is an example of which immunity type?", "a": "Passive", "lecture": "4.13 Vaccination", "level": "understanding"}, {"q": "Neuraminidase inhibitors are used against which virus?", "a": "Influenza", "lecture": "4.10 Anti-Viral Agents", "level": "recall"}, {"q": "Name secondary lymphoid organs filtering blood.", "a": "Spleen", "lecture": "4.2 Lymphoid Tissues", "level": "recall"}], "saq": [{"q": "Compare active and passive immunisation, giving one clinical example of each.", "a": "Active immunisation stimulates the host adaptive system to generate lasting memory (e.g. vaccines). Passive immunisation transfers ready-made antibodies for immediate temporary protection (e.g. IVIG, antivenom, maternal IgG).", "lecture": "4.13 Vaccination", "level": "understanding"}, {"q": "Outline the pathophysiology of type I hypersensitivity leading to anaphylaxis.", "a": "Prior sensitisation produces allergen-specific IgE bound to mast cells/basophils. Re-exposure cross-links IgE, causing degranulation with histamine and mediators → vasodilation, permeability, bronchospasm, and potentially shock.", "lecture": "4.9 Anaphylaxis", "level": "application"}, {"q": "Explain how MHC class I versus class II pathways direct different T-cell responses.", "a": "MHC I presents cytosolic peptides to CD8 T cells (kill infected/abnormal cells). MHC II on APCs presents extracellular/processed peptides to CD4 T cells, which help B cells and orchestrate adaptive responses.", "lecture": "4.6 Lymphocytes", "level": "understanding"}, {"q": "Describe two strategies pathogens use to evade the immune system.", "a": "Examples: antigenic variation; latency; downregulation of MHC I; inhibition of phagosome–lysosome fusion; capsule preventing phagocytosis; molecular mimicry; secretion of immunomodulatory proteins. (Any two well explained.)", "lecture": "4.8 Immune Evasion", "level": "recall"}, {"q": "A patient develops watery diarrhoea after broad-spectrum antibiotics. Explain the likely mechanism involving C. difficile.", "a": "Antibiotics deplete competing gut flora. C. difficile can overgrow and produce toxins that damage colonic epithelium, causing colitis/diarrhoea. Risk is higher with broad-spectrum agents and hospital exposure.", "lecture": "4.5 Diagnostic Bacteriology II", "level": "application"}, {"q": "Why are live vaccines usually contraindicated in markedly immunocompromised patients?", "a": "Attenuated organisms may cause disease if host immunity cannot control limited replication. Killed/subunit vaccines are generally safer though sometimes less immunogenic.", "lecture": "4.13 Vaccination", "level": "inference"}, {"q": "Explain the principle of PCR and why nested or real-time PCR is useful in viral diagnostics.", "a": "PCR uses primers and a thermostable polymerase to amplify specific nucleic acid sequences through thermal cycles. Nested PCR increases specificity; qPCR quantifies product in real time (e.g. viral load).", "lecture": "4.11 Diagnostic Virology I", "level": "understanding"}, {"q": "Distinguish the four classical hypersensitivity types with one example each.", "a": "I: IgE/mast cell (anaphylaxis, allergy). II: IgG/IgM against cell surfaces (autoimmune haemolysis, ABO mismatch). III: immune complexes (serum sickness, SLE nephritis). IV: T-cell delayed (TB skin test, contact dermatitis).", "lecture": "4.15 Hypersensitivity", "level": "recall"}, {"q": "Outline how innate recognition of PAMPs initiates an adaptive response.", "a": "PRRs on innate cells detect PAMPs → cytokine/chemokine release, inflammation, and dendritic cell activation/maturation. Activated DCs migrate to lymph nodes and present antigen with costimulation to naïve T cells, linking innate to adaptive immunity.", "lecture": "4.14 Immune Response to Infection", "level": "inference"}, {"q": "Explain central tolerance and what may happen if it fails.", "a": "In thymus/bone marrow, strongly self-reactive clones are deleted or diverted (e.g. Treg selection). Failure can allow autoreactive lymphocytes to mature, contributing to autoimmune disease; peripheral tolerance mechanisms normally provide backup.", "lecture": "4.7 Immune Tolerance", "level": "understanding"}, {"q": "How does selective toxicity underpin antibacterial therapy, using cell wall synthesis as an example?", "a": "Antibacterials target structures/processes essential to microbes but absent/different in humans. β-lactams inhibit peptidoglycan cross-linking in bacterial walls—humans lack peptidoglycan—yielding selective toxicity.", "lecture": "4.3 Antimicrobial Therapies", "level": "application"}, {"q": "A baby born to an HIV-positive mother has positive HIV serology at 6 weeks. Discuss interpretation and a better confirmatory approach.", "a": "Maternal IgG crosses the placenta and can persist, so antibody tests may be positive without infant infection. Nucleic acid testing (e.g. HIV RNA/DNA PCR) is used to diagnose infection in young infants.", "lecture": "4.12 Diagnostic Virology II", "level": "application"}]}, "genetics": {"sba": [{"q": "Autosomal dominant inheritance typically means:", "a": "One mutant allele is sufficient to express the phenotype", "options": ["One mutant allele is sufficient to express the phenotype", "Both alleles must be mutant to express the phenotype", "Only males are affected", "The trait skips every generation always"], "lecture": "5.1 Modes of Inheritance", "level": "recall"}, {"q": "Autosomal recessive disease in a child of unaffected parents most likely implies:", "a": "Both parents are heterozygous carriers", "options": ["Both parents are heterozygous carriers", "Both parents are homozygous affected", "Father alone transmitted a Y-linked allele", "Mitochondrial inheritance from father"], "lecture": "5.1 Modes of Inheritance", "level": "application"}, {"q": "X-linked recessive disorders are more often clinically expressed in:", "a": "Males (hemizygous for X)", "options": ["Males (hemizygous for X)", "Females only", "Equally in both sexes always", "Only postmenopausal women"], "lecture": "5.1 Modes of Inheritance", "level": "understanding"}, {"q": "Trisomy 21 is an example of:", "a": "Aneuploidy", "options": ["Aneuploidy", "A single nucleotide polymorphism only", "Trinucleotide expansion only", "Mitochondrial deletion only"], "lecture": "5.2 Chromosomal Abnormalities", "level": "recall"}, {"q": "Nondisjunction in meiosis primarily leads to:", "a": "Gametes with extra or missing chromosomes", "options": ["Gametes with extra or missing chromosomes", "Only silent synonymous codon changes", "Only epigenetic methylation changes", "Always balanced reciprocal translocation without risk"], "lecture": "5.2 Chromosomal Abnormalities", "level": "understanding"}, {"q": "Complex (multifactorial) diseases are characterised by:", "a": "Combined effects of multiple genes and environment", "options": ["Combined effects of multiple genes and environment", "Strict Mendelian single-gene causation only", "Only chromosomal trisomies", "Only spontaneous new mutations each generation"], "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "understanding"}, {"q": "Pharmacogenetics is best described as:", "a": "How genetic variation affects drug response and toxicity", "options": ["How genetic variation affects drug response and toxicity", "Only the chemistry of tablet coatings", "Only bacterial resistance mechanisms", "Only vaccine cold-chain logistics"], "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "recall"}, {"q": "Osteogenesis imperfecta (“brittle bone disease”) commonly involves defects in:", "a": "Collagen (often type I)", "options": ["Collagen (often type I)", "Haemoglobin β-chain only", "Dystrophin only", "Factor VIII only"], "lecture": "5.4 Brittle Bones", "level": "recall"}, {"q": "A germline mutation in a tumour suppressor such as BRCA1 increases cancer risk mainly by:", "a": "Impairing DNA repair / genomic stability across cells of the body", "options": ["Impairing DNA repair / genomic stability across cells of the body", "Affecting only one somatic cell forever", "Increasing dietary iron absorption only", "Blocking MHC class II expression only"], "lecture": "5.6 Cancer Genetics", "level": "inference"}, {"q": "Proto-oncogenes become oncogenes when:", "a": "Gain-of-function changes hyperactivate growth signalling", "options": ["Gain-of-function changes hyperactivate growth signalling", "Both copies are deleted like classic tumour suppressors only", "They solely encode structural ribosomal RNA", "They are never expressed in any cancer"], "lecture": "5.6 Cancer Genetics", "level": "understanding"}, {"q": "Which testing approach sequences many genes relevant to a phenotype in parallel?", "a": "Gene panel / next-generation sequencing panel", "options": ["Gene panel / next-generation sequencing panel", "Only karyotype for single-gene SNVs", "Only blood film morphology", "Only ESR"], "lecture": "5.7 Genetic Testing", "level": "recall"}, {"q": "Incomplete penetrance means:", "a": "Not everyone with the genotype shows the phenotype", "options": ["Not everyone with the genotype shows the phenotype", "The phenotype is always identical in severity", "Only mitochondrial DNA is involved", "The allele is never transmitted"], "lecture": "5.8 Phenotypic Variability", "level": "understanding"}, {"q": "Variable expressivity means:", "a": "Severity/features differ among genotype-positive individuals", "options": ["Severity/features differ among genotype-positive individuals", "The genotype is never pathogenic", "Only one sex can inherit the allele", "Penetrance is always 100% with identical features"], "lecture": "5.8 Phenotypic Variability", "level": "understanding"}, {"q": "CRISPR-based approaches for genetic disease aim primarily to:", "a": "Edit or modulate specific DNA sequences", "options": ["Edit or modulate specific DNA sequences", "Replace all chromosomes each cell division", "Only measure karyotypes", "Only inhibit platelet aggregation"], "lecture": "5.9 Emerging Treatments", "level": "recall"}, {"q": "A balanced reciprocal translocation carrier is usually healthy but has increased risk of:", "a": "Unbalanced gametes and affected offspring", "options": ["Unbalanced gametes and affected offspring", "Immediate trisomy in every cell of their body", "Inability to produce any gametes always", "Only mitochondrial disease"], "lecture": "5.2 Chromosomal Abnormalities", "level": "application"}, {"q": "Mitochondrial DNA disorders are transmitted:", "a": "From the mother (maternal inheritance)", "options": ["From the mother (maternal inheritance)", "Only from father to son", "Only autosomal recessive", "Never inherited"], "lecture": "5.1 Modes of Inheritance", "level": "recall"}, {"q": "A pathogenic BRCA variant is identified in a family. Cascade testing of relatives is mainly to:", "a": "Identify carriers for risk-reducing options and surveillance", "options": ["Identify carriers for risk-reducing options and surveillance", "Treat already established metastases only", "Replace chemotherapy for all cancers", "Diagnose bacterial infection"], "lecture": "5.6 Cancer Genetics", "level": "application"}, {"q": "SNP association studies in complex disease typically identify:", "a": "Risk alleles of small effect that contribute probabilistically", "options": ["Risk alleles of small effect that contribute probabilistically", "A single mutation that is necessary and sufficient in all cases", "Only large chromosomal trisomies", "Only non-genetic environmental causes"], "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "inference"}, {"q": "Anticipation in some repeat-expansion disorders refers to:", "a": "Earlier/more severe disease in successive generations as repeats expand", "options": ["Earlier/more severe disease in successive generations as repeats expand", "Complete disappearance of disease each generation", "Only maternal imprinting without repeats", "Always milder disease in grandchildren"], "lecture": "5.8 Phenotypic Variability", "level": "understanding"}, {"q": "Gene therapy using a viral vector must balance transduction efficiency against:", "a": "Immune responses and insertional risks", "options": ["Immune responses and insertional risks", "Only the cost of karyotyping", "Only ABO matching of erythrocytes", "Only gastric pH"], "lecture": "5.9 Emerging Treatments", "level": "inference"}], "vsaq": [{"q": "Inheritance pattern needing two mutant alleles for disease?", "a": "Autosomal recessive", "lecture": "5.1 Modes of Inheritance", "level": "recall"}, {"q": "Inheritance pattern where one mutant allele causes disease?", "a": "Autosomal dominant", "lecture": "5.1 Modes of Inheritance", "level": "recall"}, {"q": "Trisomy 21 is also called?", "a": "Down syndrome", "lecture": "5.2 Chromosomal Abnormalities", "level": "recall"}, {"q": "Failure of chromosomes to separate in meiosis?", "a": "Nondisjunction", "lecture": "5.2 Chromosomal Abnormalities", "level": "recall"}, {"q": "Study of genetic effects on drug response?", "a": "Pharmacogenetics", "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "recall"}, {"q": "Brittle bone disease commonly involves which protein?", "a": "Collagen", "lecture": "5.4 Brittle Bones", "level": "recall"}, {"q": "Name a major breast/ovarian cancer susceptibility gene.", "a": ["BRCA1", "BRCA2"], "lecture": "5.6 Cancer Genetics", "level": "recall"}, {"q": "Not all genotype carriers show phenotype: term?", "a": "Incomplete penetrance", "lecture": "5.8 Phenotypic Variability", "level": "understanding"}, {"q": "Same genotype, different severity: term?", "a": "Variable expressivity", "lecture": "5.8 Phenotypic Variability", "level": "understanding"}, {"q": "Mitochondrial DNA is inherited from which parent?", "a": "Mother", "lecture": "5.1 Modes of Inheritance", "level": "recall"}, {"q": "Extra or missing chromosomes: term?", "a": "Aneuploidy", "lecture": "5.2 Chromosomal Abnormalities", "level": "recall"}, {"q": "Gene-editing system using guide RNA?", "a": "CRISPR", "lecture": "5.9 Emerging Treatments", "level": "recall"}, {"q": "Males express X-linked recessive traits more: why hemizygous?", "a": "One X", "lecture": "5.1 Modes of Inheritance", "level": "understanding"}, {"q": "Tumour suppressor needing two hits typically?", "a": ["Both alleles", "Two alleles"], "lecture": "5.6 Cancer Genetics", "level": "understanding"}, {"q": "Multifactorial disease involves genes plus?", "a": "Environment", "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "recall"}, {"q": "Karyotyping detects mainly what scale of change?", "a": ["Chromosomal", "Large rearrangements", "Aneuploidy"], "lecture": "5.7 Genetic Testing", "level": "understanding"}, {"q": "Cascade testing screens which group after a familial variant?", "a": "Relatives", "lecture": "5.6 Cancer Genetics", "level": "application"}, {"q": "Earlier onset in successive generations of repeat disease?", "a": "Anticipation", "lecture": "5.8 Phenotypic Variability", "level": "recall"}], "saq": [{"q": "Distinguish autosomal dominant and autosomal recessive inheritance using recurrence risk ideas for offspring of two carrier parents versus an affected AD parent.", "a": "AD: an affected heterozygote typically has 50% risk of transmitting the allele each child. AR: two carrier parents have 25% risk of an affected child, 50% carriers, 25% non-carriers each pregnancy (assuming complete penetrance).", "lecture": "5.1 Modes of Inheritance", "level": "application"}, {"q": "Explain how meiotic nondisjunction leads to Down syndrome, and why maternal age is a risk factor in many cases.", "a": "Nondisjunction yields gametes with an extra chromosome 21; fertilisation produces trisomy 21. Risk rises with maternal age because meiosis I arrest in oocytes is prolonged, increasing chance of segregation errors.", "lecture": "5.2 Chromosomal Abnormalities", "level": "understanding"}, {"q": "Why do complex diseases not follow simple Mendelian ratios, and how do GWAS contribute?", "a": "Many loci of small effect plus environment determine risk, so pedigrees lack clear single-gene patterns. GWAS associate SNPs with disease risk across populations, highlighting pathways rather than guaranteeing causation in individuals.", "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "inference"}, {"q": "Give an example of a pharmacogenetic interaction and why it matters clinically.", "a": "Example: CYP2C9/VKORC1 variants affect warfarin dose requirement/bleeding risk; TPMT variants affect thiopurine toxicity; HLA-B*5701 and abacavir hypersensitivity. Testing can guide dose or drug choice to improve safety/efficacy.", "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "application"}, {"q": "Describe how collagen defects cause brittle bones in osteogenesis imperfecta.", "a": "Type I collagen is critical for bone tensile strength. Qualitative or quantitative collagen defects weaken bone matrix, leading to fractures, bone deformity, and other connective-tissue features depending on type/severity.", "lecture": "5.4 Brittle Bones", "level": "understanding"}, {"q": "Compare oncogenes and tumour suppressor genes in cancer genetics, with inheritance implications for germline predisposition.", "a": "Oncogenes: gain-of-function drivers (often somatic). Tumour suppressors: loss-of-function; germline heterozygous mutation plus somatic second hit explains dominant cancer predisposition pedigrees (Knudson two-hit).", "lecture": "5.6 Cancer Genetics", "level": "understanding"}, {"q": "A healthy balanced translocation carrier asks about reproductive risks. What do you explain?", "a": "Their somatic karyotype is balanced so they are usually well, but meiosis can produce unbalanced gametes. This raises risks of miscarriage or offspring with partial trisomy/monosomy; reproductive options and testing can be discussed.", "lecture": "5.2 Chromosomal Abnormalities", "level": "application"}, {"q": "Define incomplete penetrance and variable expressivity and explain why they complicate genetic counselling.", "a": "Incomplete penetrance: genotype without phenotype in some individuals. Variable expressivity: differing severity/features among those affected. Counselling must avoid absolute predictions and discuss ranges of outcomes and surveillance.", "lecture": "5.8 Phenotypic Variability", "level": "inference"}, {"q": "Outline ethical issues raised by predictive genetic testing for late-onset disease.", "a": "Issues include autonomy, informed consent, psychological impact, privacy, possible insurance/employment discrimination, testing of minors, and implications for relatives who may not wish to know.", "lecture": "5.7 Genetic Testing", "level": "inference"}, {"q": "Describe the promise and risks of gene therapy / genome editing for monogenic disease.", "a": "Promise: durable correction of the underlying defect. Risks: immune reactions to vectors, insertional mutagenesis, off-target edits, incomplete efficacy, and ethical concerns about germline editing.", "lecture": "5.9 Emerging Treatments", "level": "understanding"}, {"q": "Why might two siblings with the same pathogenic variant show different severity?", "a": "Modifier genes, environmental factors, stochastic effects, mosaicism, allelic variation, and epigenetic influences can alter expressivity even with the same primary variant.", "lecture": "5.8 Phenotypic Variability", "level": "inference"}, {"q": "Explain maternal inheritance of mitochondrial disorders and heteroplasmy.", "a": "mtDNA is transmitted through the oocyte. Cells can contain mixed mutant/wild-type mtDNA (heteroplasmy); the proportion influences phenotype severity and tissue distribution, producing variable expression.", "lecture": "5.1 Modes of Inheritance", "level": "understanding"}]}}};
